def _normalize_action(action: str) -> str:
    if not action:
        return ""
    a = action.strip()
    if len(a) >= 2 and a[0] == '"' and a[-1] == '"':
        a = a[1:-1].strip()
    if "#" in a:
        a = a.split("#", 1)[1]
    if "/" in a:
        a = a.rsplit("/", 1)[-1]
    if ":" in a:
        a = a.rsplit(":", 1)[-1]
    return a


